#!/usr/bin/env python3\nimport paramiko\nimport time\n\nHOST = "168.119.79.238"\nPORT = 77\nUSERNAME = "sanliur"\nPASSWORD = "CHANGE_ME_CWP_SSH_PASSWORD"\n\ndef main():\n    ssh = paramiko.SSHClient()\n    ssh.set_missing_host_key_policy(paramiko.AutoAddPolicy())\n    ssh.connect(HOST, port=PORT, username=USERNAME, password=PASSWORD, \n                timeout=20, look_for_keys=False, allow_agent=False)\n    \n    channel = ssh.invoke_shell()\n    time.sleep(2)\n    \n    print("Fixing PostgreSQL...")\n    \n    # Fix auth\n    channel.send("sudo sed -i 's/scram-sha-256/trust/g' /var/lib/pgsql/data/pg_hba.conf\n")\n    time.sleep(2)\n    channel.send("sudo sed -i 's/ident/trust/g' /var/lib/pgsql/data/pg_hba.conf\n")\n    time.sleep(2)\n    channel.send("sudo sed -i 's/md5/trust/g' /var/lib/pgsql/data/pg_hba.conf\n")\n    time.sleep(2)\n    channel.send("sudo systemctl restart postgresql\n")\n    time.sleep(5)\n    \n    # Create tables\n    channel.send("cd /home/sanliur/public_html\n")\n    time.sleep(1)\n    channel.send("psql -U sanliur_sanliurfa -d sanliur_sanliurfa -h localhost -f database/schema.sql 2>&1 | tail -5\n")\n    time.sleep(5)\n    \n    output = ""\n    while channel.recv_ready():\n        output += channel.recv(4096).decode('utf-8', errors='ignore')\n        time.sleep(1)\n    \n    print(output[-400:])\n    \n    channel.close()\n    ssh.close()\n    print("Done!")\n\nif __name__ == "__main__":\n    main()\n
